# 📌 PART 1: WHAT ARE CLASSES? 📌
# ═════════════════════════════════════════════════════════════════════════════

"""
A CLASS is a blueprint or "template" for creating objects (instances).

Analogy: 
  🏠 A class is like the blueprint of a house.
  🏠 An object is a real house built following that blueprint.

Why use classes?
  ✅ Organize code
  ✅ Reuse code
  ✅ Simulate real-world objects
  ✅ Facilitate maintenance
"""

# ═════════════════════════════════════════════════════════════════════════════
# 📌 PART 2: BASIC SYNTAX 📌
# ═════════════════════════════════════════════════════════════════════════════

"""
The basic syntax of a class in Python:

    class ClassName:
        def __init__(self, parameters):
            # Initialize attributes
            self.attribute = value
        
        def method(self):
            # Method code
            pass
"""

# ═════════════════════════════════════════════════════════════════════════════
# 📌 EXAMPLE 1: SIMPLE CLASS - PERSON 📌
# ═════════════════════════════════════════════════════════════════════════════

class Person:
    """
    A simple class that represents a Person.
    Demonstrates basic concepts: attributes and methods.
    """
    
    # Constructor (special method __init__)
    # This method is called automatically when you create an object
    def __init__(self, name: str, age: int):
        """
        Define the initial attributes of the object.
        
        Args:
            name (str): Name of the person
            age (int): Age of the person
        """
        self.name = name  # Attribute: stores the name
        self.age = age  # Attribute: stores the age
    
    def introduce(self) -> None:
        """Method that displays an introduction of the person."""
        print(f"👋 Hello! My name is {self.name} and I'm {self.age} years old.")
    
    def have_birthday(self) -> None:
        """Method that increments the age by 1 year."""
        self.age += 1
        print(f"🎂 Happy birthday! {self.name} is now {self.age} years old!")
    
    def get_information(self) -> str:
        """Returns the person's information as a string."""
        return f"Name: {self.name} | Age: {self.age} years"


# 🔹 USING THE PERSON CLASS
print("\n" + "="*70)
print("🔹 EXAMPLE 1: Using the Person Class")
print("="*70)

person1 = Person("John", 25)  # Creating an instance (object)
person1.introduce()  # Calling a method
print(f"📋 {person1.get_information()}")

person1.have_birthday()  # Calling another method


# ═════════════════════════════════════════════════════════════════════════════
# 📌 EXAMPLE 2: CLASS WITH PRIVATE ATTRIBUTES 📌
# ═════════════════════════════════════════════════════════════════════════════

class BankAccount:
    """
    A class that represents a Bank Account.
    Demonstrates the concept of ENCAPSULATION (private attributes).
    """
    
    def __init__(self, holder: str, initial_balance: float = 0.0):
        """
        Initializes a bank account.
        
        Args:
            holder (str): Name of the account holder
            initial_balance (float): Initial account balance (default: 0.0)
        """
        self.holder = holder
        self.__balance = initial_balance  # __ indicates it's private (don't access directly)
        self.__history = []  # Records all transactions
    
    def deposit(self, amount: float) -> None:
        """Makes a deposit to the account."""
        if amount <= 0:
            print("❌ Error: Amount must be positive!")
            return
        
        self.__balance += amount
        self.__history.append(f"✅ Deposit: +${amount:.2f}")
        print(f"💰 Deposit of ${amount:.2f} made successfully!")
    
    def withdraw(self, amount: float) -> None:
        """Makes a withdrawal from the account."""
        if amount <= 0:
            print("❌ Error: Amount must be positive!")
            return
        
        if amount > self.__balance:
            print(f"❌ Error: Insufficient balance! Your balance is ${self.__balance:.2f}")
            return
        
        self.__balance -= amount
        self.__history.append(f"❌ Withdrawal: -${amount:.2f}")
        print(f"💵 Withdrawal of ${amount:.2f} made successfully!")
    
    def check_balance(self) -> float:
        """Returns the current account balance."""
        return self.__balance
    
    def display_balance(self) -> None:
        """Displays the balance in a formatted way."""
        print(f"💳 [{self.holder}] Balance: ${self.__balance:.2f}")
    
    def view_history(self) -> None:
        """Displays the transaction history."""
        print(f"\n📜 HISTORY FOR {self.holder}:")
        if not self.__history:
            print("   No transactions yet.")
        else:
            for transaction in self.__history:
                print(f"   {transaction}")


# 🔹 USING THE BANK ACCOUNT CLASS
print("\n" + "="*70)
print("🔹 EXAMPLE 2: Using the BankAccount Class")
print("="*70)

account = BankAccount("Maria Silva", 1000.0)
account.display_balance()

account.deposit(500)
account.withdraw(200)
account.display_balance()

account.view_history()


# ═════════════════════════════════════════════════════════════════════════════
# 📌 EXAMPLE 3: INHERITANCE (Subclasses) 📌
# ═════════════════════════════════════════════════════════════════════════════

"""
INHERITANCE allows a class to INHERIT attributes and methods from another class.

Example:
    class Animal:        <- PARENT class (superclass)
        pass
    
    class Dog(Animal):  <- CHILD class (subclass)
        pass
"""

class Animal:
    """PARENT class - Represents a generic animal."""
    
    def __init__(self, name: str, age: int):
        self.name = name
        self.age = age
    
    def make_sound(self) -> None:
        """Method that the subclass can override."""
        print(f"🔊 {self.name} makes a sound!")


class Dog(Animal):
    """CHILD class - Inherits from Animal and adds its own characteristics."""
    
    def __init__(self, name: str, age: int, breed: str):
        super().__init__(name, age)  # Calls the PARENT class constructor
        self.breed = breed
    
    def make_sound(self) -> None:
        """Override the PARENT class method."""
        print(f"🐕 {self.name} barks: Woof woof woof!")
    
    def fetch_ball(self) -> None:
        """Method exclusive to the Dog class."""
        print(f"🎾 {self.name} ran after the ball!")


class Cat(Animal):
    """Another CHILD class - Inherits from Animal."""
    
    def make_sound(self) -> None:
        """Override the PARENT class method."""
        print(f"🐱 {self.name} meows: Meow meow!")
    
    def scratch_sofa(self) -> None:
        """Method exclusive to the Cat class."""
        print(f"😼 {self.name} scratched the sofa! (Oops!)")


# 🔹 USING INHERITANCE
print("\n" + "="*70)
print("🔹 EXAMPLE 3: Using Inheritance")
print("="*70)

dog = Dog("Rex", 3, "Labrador")
dog.make_sound()
dog.fetch_ball()

cat = Cat("Mimi", 2)
cat.make_sound()
cat.scratch_sofa()


