# 📌 EXAMPLE 4: MORE COMPLETE CLASS - PRODUCT 📌
# ═════════════════════════════════════════════════════════════════════════════

class Product:
    """
    Class that represents a Product in a store.
    Demonstrates attributes, methods and useful operations.
    """
    
    def __init__(self, name: str, price: float, quantity: int):
        self.name = name
        self.price = price
        self.quantity = quantity
    
    def calculate_total_value(self) -> float:
        """Calculates the total value of the stock."""
        return self.price * self.quantity
    
    def apply_discount(self, percentage: float) -> None:
        """Applies a percentage discount to the price."""
        discount = self.price * (percentage / 100)
        self.price -= discount
        print(f"🏷️  {percentage}% discount applied! New price: ${self.price:.2f}")
    
    def sell(self, quantity: int) -> bool:
        """Sells a quantity of products."""
        if quantity > self.quantity:
            print(f"❌ Error: Only {self.quantity} units available!")
            return False
        
        self.quantity -= quantity
        print(f"✅ {quantity} unit(s) of '{self.name}' sold!")
        return True
    
    def restock(self, quantity: int) -> None:
        """Restocks the inventory."""
        self.quantity += quantity
        print(f"📦 Stock replenished! Now there are {self.quantity} units.")
    
    def display_information(self) -> None:
        """Displays all product information."""
        print(f"\n📦 PRODUCT: {self.name}")
        print(f"   💵 Price: ${self.price:.2f}")
        print(f"   📊 Quantity: {self.quantity} units")
        print(f"   💰 Total Value: ${self.calculate_total_value():.2f}")


# 🔹 USING THE PRODUCT CLASS
print("\n" + "="*70)
print("🔹 EXAMPLE 4: Using the Product Class")
print("="*70)

product1 = Product("Laptop", 3500.00, 5)
product1.display_information()

product1.sell(2)
product1.apply_discount(10)
product1.display_information()


